const body = $json.body || {};
const sig = $json.headers?.['x-hub-signature-256'] || '';
const event = $json.headers?.['x-github-event'] || '';

if (event !== 'pull_request') {
  return [{ json: { skip: true, reason: 'Not a pull_request event' } }];
}

const action = body.action;
if (!['opened', 'reopened', 'ready_for_review'].includes(action)) {
  return [{ json: { skip: true, reason: `Ignored action: ${action}` } }];
}

const secret = $env.GITHUB_WEBHOOK_SECRET;
if (!secret) {
  return [{ json: { skip: true, reason: 'GITHUB_WEBHOOK_SECRET not configured' } }];
}

const crypto = require('crypto');
const payload = JSON.stringify(body);
const expected = `sha256=${crypto.createHmac('sha256', secret).update(payload).digest('hex')}`;
if (!sig || !crypto.timingSafeEqual(Buffer.from(sig), Buffer.from(expected))) {
  return [{ json: { skip: true, reason: 'Invalid webhook signature' } }];
}

const pr = body.pull_request || {};
const repo = body.repository || {};
return [{
  json: {
    skip: false,
    owner: repo.owner?.login,
    repo: repo.name,
    pr_number: pr.number,
    pr_title: pr.title || '',
    pr_body: pr.body || '',
    commits_url: pr.commits_url,
    files_url: pr.url + '/files',
    issue_url: pr.issue_url,
    compare_url: pr.diff_url
  }
}];

