const meta = $('Build AI Prompt').first().json;
const text = $json.choices?.[0]?.message?.content?.trim();
if (!text) {
  return [{ json: { ...meta, skip: true, reason: 'No model output' } }];
}

return [{
  json: {
    ...meta,
    body: text
  }
}];
